        var result = [];
        if( this.editor && this.editor.document ){
            var images = this.editor.document.find("img");
            if (images) {
                for (var i = 0; i < images.$.length; i++) {
                    result.push(images.getItem(i).$);
                }
            }
            return result;
        }else{
            return this.node.getElements("img");
        }
